class Node:
    def __init__(self, data):
        self.data = data
        self.next = None

class LinkedList:
    def __init__(self):
        self.head = None

    def push(self, new_data):
        new_node = Node(new_data)
        new_node.next = self.head
        self.head = new_node

    def delete_n_after_m(self, m, n):
        if not self.head or m < 0 or n < 0:
            return

        if m == 0:
            current = self.head
            for _ in range(n):
                if current:
                    current = current.next
                else:
                    break
            self.head = current
            return

        current = self.head
        count = 0
        while current and count < m - 1:
            current = current.next
            count += 1

        if not current or not current.next:
            return

        node_before_deletion = current

        temp = node_before_deletion.next
        for _ in range(n):
            if temp:
                temp = temp.next
            else:
                break

        node_before_deletion.next = temp

    def print_list(self):
        temp = self.head
        while temp:
            print(temp.data, end=" -> ")
            temp = temp.next
        print("None")
